import { FC } from 'react';

import {
  ItemProps,
  PriceComparisonComponentProps,
} from '../PriceComparison.types';

import Button from './Button';
import Fallback from './Fallback';
import Loading from './Loading';
import { Wrapper, Buttons } from './PriceComparisonAsButtons.styles';

const PriceComparisonAsButtons: FC<PriceComparisonComponentProps> = ({
  className,
  items,
  isLoading,
  isFallback,
}) => {
  const ButtonsComponent = () => (
    <Buttons
      items={items}
      renderItems={({ merchant, price, link }: ItemProps) => {
        return <Button merchant={merchant} price={price} link={link} />;
      }}
    />
  );

  if (isLoading) {
    return <Loading className={className} />;
  }

  if (isFallback) {
    return <Fallback className={className} Component={ButtonsComponent} />;
  }

  return (
    <Wrapper className={className}>
      <ButtonsComponent />
    </Wrapper>
  );
};

export default PriceComparisonAsButtons;
