import { FC } from 'react';

import {
  BUTTON_AS_ANCHOR,
  BUTTON_SIZE_LARGE,
  BUTTON_VARIANT_E_COMMERCE,
} from '#components/Button/Button.constants';

import { getPriceWithoutDecimals } from '../PriceComparison';
import { ItemProps } from '../PriceComparison.types';

import {
  Item,
  StyledButton,
  TextWithTruncation,
} from './PriceComparisonAsButtons.styles';

const Button: FC<ItemProps> = ({ merchant, price, link }) => (
  <Item>
    <StyledButton
      forwardedAs={BUTTON_AS_ANCHOR}
      href={link}
      target="_blank"
      rel="noreferrer"
      isExternal={true}
      size={BUTTON_SIZE_LARGE}
      variant={BUTTON_VARIANT_E_COMMERCE}
    >
      <TextWithTruncation>
        {getPriceWithoutDecimals(price)} from {merchant}
      </TextWithTruncation>
    </StyledButton>
  </Item>
);

export default Button;
